using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change 1: EF Core 9 renamed the default discriminator
            // property from "Discriminator" to "$type". Existing 500K documents
            // store "Discriminator", and direct SQL queries reference c.Discriminator,
            // so we must preserve the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF Core 9 no longer includes the discriminator
            // value in the JSON "id" property. EF8 wrote ids as "Product|123";
            // EF9 defaults to just "123". Without this, EF9 cannot find any
            // existing documents by key.
            entity.HasDiscriminatorInJsonId();

            // Breaking change 3: HasIndex() now throws for the Cosmos provider
            // because Cosmos manages indexing server-side via its own indexing
            // policy. The previous HasIndex(p => p.Sku) call has been removed.
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

